/**
 * Run the ChronicleDB memory eval against a fixed set of questions.
 *
 * Loads questions.json (generated by generate_questions.ts) and runs each
 * question through 3 models × 2 conditions (chronicle-db block / baseline).
 * Saves results to eval/results/run-<timestamp>.json.
 *
 * Usage:
 *   tsx scripts/run_eval.ts           # full eval (all questions)
 *   tsx scripts/run_eval.ts --dry-run # first 5 questions only
 *   tsx scripts/run_eval.ts --n=10    # first N questions
 */

import "dotenv/config";
import { readFileSync, writeFileSync, existsSync, mkdirSync } from "fs";
import { resolve } from "path";
import { chat } from "../lib/proxy.js";
import { retrieve, closePool } from "../lib/cdb-client.js";
import { CHAT_ID, CHARACTER_NAME, USER_NAME, loadCorpus, PREAMBLE } from "../lib/corpus.js";

const QUESTIONS_PATH = resolve(import.meta.dirname, "..", "questions.json");
const RESULTS_DIR = resolve(import.meta.dirname, "..", "results");

// Models to test — can override via env
const MODELS = {
  strong: process.env.STRONG_MODEL || "claude-sonnet-4.6",
  mid: process.env.MID_MODEL || "gemini-3.1-pro-preview",
  cheap: process.env.CHEAP_MODEL || "gemma-4-31b-it",
};

interface Question {
  id: string;
  question: string;
  ground_truth: string;
  source_chunk: string;
  chunk_offset: number;
}

interface AnswerResult {
  question_id: string;
  model: string;
  condition: string; // e.g. "raw-16k-only", "raw-32k-plus-cdb"
  answer: string;
  context_chars: number;
  memory_block_chars: number;
  latency_ms: number;
  error?: string;
}

const ANSWER_PROMPT = `Based on the context below, answer this question precisely. If the context doesn't contain the answer, say "I don't know".

Context:
{context}

Question: {question}

Answer:`;

async function answer(
  model: string,
  question: string,
  context: string,
): Promise<string> {
  const prompt = ANSWER_PROMPT
    .replace("{context}", context || "(no context)")
    .replace("{question}", question);

  return await chat(
    model,
    [{ role: "user", content: prompt }],
    { temperature: 0.1, max_tokens: 300 },
  );
}

// Context sizes to test (in tokens; ~4 chars per token).
// Override via SIZES env var: comma-separated labels (16k,32k,55k).
// Default: 16k + 32k. 55k is opt-in because it ~6× the input cost of 16k
// and the marginal information gain is usually small.
const ALL_CONTEXT_SIZES = [
  { label: "16k", tokens: 16000 },
  { label: "32k", tokens: 32000 },
  { label: "55k", tokens: 55000 },
];
const SIZES_ENV = (process.env.SIZES || "16k,32k").split(",").map((s) => s.trim());
const CONTEXT_SIZES = ALL_CONTEXT_SIZES.filter((s) => SIZES_ENV.includes(s.label));
if (CONTEXT_SIZES.length === 0) {
  console.error(`No context sizes selected. SIZES=${process.env.SIZES} matched none of: 16k,32k,55k`);
  process.exit(1);
}

/**
 * Build the context for a given token budget:
 *   char_card + persona_card + tail_messages
 *
 * Real ST requests always include the character card + user persona,
 * then as many recent messages as fit. We replicate that structure.
 *
 * Memory block (if provided) is injected AFTER the preamble but BEFORE
 * the chat history, which matches where ChronicleDB's setExtensionPrompt
 * injects in the real ST pipeline.
 */
function buildContext(
  fullChat: string,
  totalTokens: number,
  memoryBlock: string = "",
): string {
  const charsBudget = totalTokens * 4;
  const preambleChars = PREAMBLE.length;
  const memoryChars = memoryBlock.length;

  // Reserve space for preamble and memory block, use rest for chat tail
  const chatBudget = charsBudget - preambleChars - memoryChars - 200; // 200 for framing
  if (chatBudget <= 0) {
    return PREAMBLE + (memoryBlock ? memoryBlock + "\n\n" : "");
  }

  const chatSlice =
    fullChat.length <= chatBudget
      ? fullChat
      : "...[earlier messages truncated]...\n\n" + fullChat.slice(fullChat.length - chatBudget);

  return (
    PREAMBLE +
    (memoryBlock ? memoryBlock + "\n\n" : "") +
    "=== CHAT HISTORY ===\n" +
    chatSlice +
    "\n=== END CHAT HISTORY ==="
  );
}

// Custom error class so the runner can detect rate limits and trip the
// circuit breaker (stop the entire eval, don't burn more tokens).
class RateLimitError extends Error {
  constructor(msg: string) {
    super(msg);
    this.name = "RateLimitError";
  }
}

function isRateLimit(msg: string): boolean {
  return /429|rate.?limit|exceeded.*token|daily.*limit|quota/i.test(msg);
}

async function runQuestion(
  q: Question,
  modelKey: keyof typeof MODELS,
  rawChat: string,
  cachedMemoryBlock: string,
  cachedRetrievalError: string | null,
): Promise<AnswerResult[]> {
  const model = MODELS[modelKey];
  const results: AnswerResult[] = [];

  // Memory block is shared across all models for this question — passed in
  // as a parameter, computed once by the caller. Saves 2/3 of embed calls.
  const memoryBlock = cachedMemoryBlock;
  const retrievalError = cachedRetrievalError;

  // For each context size, run both raw-only and raw+cdb
  for (const size of CONTEXT_SIZES) {
    // raw-only: char card + persona + tail messages, NO ChronicleDB
    try {
      const t0 = Date.now();
      const context = buildContext(rawChat, size.tokens, "");
      const ans = await answer(model, q.question, context);
      results.push({
        question_id: q.id,
        model,
        condition: `raw-${size.label}-only`,
        answer: ans,
        context_chars: context.length,
        memory_block_chars: 0,
        latency_ms: Date.now() - t0,
      });
    } catch (err) {
      const msg = (err as Error).message;
      results.push({
        question_id: q.id,
        model,
        condition: `raw-${size.label}-only`,
        answer: "",
        context_chars: 0,
        memory_block_chars: 0,
        latency_ms: 0,
        error: msg,
      });
      if (isRateLimit(msg)) throw new RateLimitError(msg);
    }

    // raw + chronicledb: char card + persona + CDB memory + tail messages
    try {
      const t0 = Date.now();
      const context = buildContext(rawChat, size.tokens, memoryBlock);
      const ans = await answer(model, q.question, context);
      results.push({
        question_id: q.id,
        model,
        condition: `raw-${size.label}-plus-cdb`,
        answer: ans,
        context_chars: context.length,
        memory_block_chars: memoryBlock.length,
        latency_ms: Date.now() - t0,
        ...(retrievalError ? { error: `retrieval: ${retrievalError}` } : {}),
      });
    } catch (err) {
      const msg = (err as Error).message;
      results.push({
        question_id: q.id,
        model,
        condition: `raw-${size.label}-plus-cdb`,
        answer: "",
        context_chars: 0,
        memory_block_chars: memoryBlock.length,
        latency_ms: 0,
        error: msg,
      });
      if (isRateLimit(msg)) throw new RateLimitError(msg);
    }
  }

  return results;
}

async function main() {
  const args = process.argv.slice(2);
  const dryRun = args.includes("--dry-run");
  const preflight = args.includes("--preflight");
  const nArg = args.find((a) => a.startsWith("--n="));
  const limit = dryRun ? 5 : preflight ? 3 : nArg ? parseInt(nArg.split("=")[1]) : undefined;

  // Filter to a single model via --model=strong|mid|cheap
  const modelArg = args.find((a) => a.startsWith("--model="));
  const singleModel = modelArg ? modelArg.split("=")[1] : null;
  const outSuffix = process.env.OUT_SUFFIX || (singleModel ? `-${singleModel}` : "");

  if (!existsSync(QUESTIONS_PATH)) {
    console.error(`${QUESTIONS_PATH} not found. Run: npm run generate`);
    process.exit(1);
  }

  const allQuestions: Question[] = JSON.parse(readFileSync(QUESTIONS_PATH, "utf-8"));
  const questions = limit ? allQuestions.slice(0, limit) : allQuestions;

  console.log("Loading corpus...");
  const { fullText, messageCount } = loadCorpus();
  console.log(`  ${messageCount} messages, ${fullText.length} chars`);

  // ── Cost estimate ───────────────────────────────────────────
  // Compute approx input tokens per condition.
  const PREAMBLE_TOK = Math.round(PREAMBLE.length / 4);
  const CDB_TOK_EST = 500; // typical memory block ~2k chars / 4
  const sizesLabel = CONTEXT_SIZES.map((s) => s.label).join("+");
  const tokensPerCondition = CONTEXT_SIZES.flatMap((s) => [
    s.tokens,        // raw-only: full budget used by preamble + chat
    s.tokens,        // raw+cdb:  same budget, smaller chat tail to make room
  ]);
  const tokensPerQuestionPerModel = tokensPerCondition.reduce((a, b) => a + b, 0);
  const numModels = singleModel ? 1 : 3;
  const totalInputTokens = questions.length * numModels * tokensPerQuestionPerModel;
  const totalCalls = questions.length * numModels * tokensPerCondition.length;

  console.log(`\nLoaded ${allQuestions.length} questions, running ${questions.length}`);
  console.log(`Models: ${(singleModel ? [MODELS[singleModel as keyof typeof MODELS]] : Object.values(MODELS)).join(", ")}`);
  console.log(`Context sizes: ${sizesLabel}`);
  console.log(`Conditions: ${CONTEXT_SIZES.length} sizes × (only | plus-cdb) = ${tokensPerCondition.length} per question per model`);
  console.log(`Total calls: ${questions.length} × ${numModels} models × ${tokensPerCondition.length} conditions = ${totalCalls}`);
  console.log(`Estimated input tokens (rough, ignores output + embeddings): ~${(totalInputTokens / 1_000_000).toFixed(2)}M`);
  console.log("");

  if (!existsSync(RESULTS_DIR)) mkdirSync(RESULTS_DIR, { recursive: true });

  const results: AnswerResult[] = [];
  const modelKeys: (keyof typeof MODELS)[] = singleModel
    ? [singleModel as keyof typeof MODELS]
    : ["strong", "mid", "cheap"];
  if (singleModel && !MODELS[singleModel as keyof typeof MODELS]) {
    console.error(`Unknown model key: ${singleModel}. Use: strong | mid | cheap`);
    process.exit(1);
  }

  // ── Output file: support resume ─────────────────────────────
  // If --resume=path is given, append to that file. Otherwise create new.
  const resumeArg = args.find((a) => a.startsWith("--resume="));
  let outPath: string;
  let resumedResults: AnswerResult[] = [];
  let processedQids = new Set<string>();

  if (resumeArg) {
    outPath = resolve(resumeArg.split("=")[1]);
    if (existsSync(outPath)) {
      const prev = JSON.parse(readFileSync(outPath, "utf-8"));
      resumedResults = prev.results || [];
      // Build set of (question_id, model, condition) tuples already done
      const done = new Set<string>();
      for (const r of resumedResults) {
        done.add(`${r.question_id}|${r.model}|${r.condition}`);
      }
      // A question is "fully done" if all model/condition combos exist
      for (const q of questions) {
        let allDone = true;
        for (const mk of modelKeys) {
          for (const size of CONTEXT_SIZES) {
            if (!done.has(`${q.id}|${MODELS[mk]}|raw-${size.label}-only`)) { allDone = false; break; }
            if (!done.has(`${q.id}|${MODELS[mk]}|raw-${size.label}-plus-cdb`)) { allDone = false; break; }
          }
          if (!allDone) break;
        }
        if (allDone) processedQids.add(q.id);
      }
      console.log(`\n[resume] ${resumedResults.length} results loaded from ${outPath}`);
      console.log(`[resume] ${processedQids.size}/${questions.length} questions already complete\n`);
    }
  } else {
    const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
    outPath = resolve(RESULTS_DIR, `run-${timestamp}${outSuffix}.json`);
  }

  // Initialize results with anything we resumed
  results.push(...resumedResults);

  // ── Persist after each question ─────────────────────────────
  const persist = () => {
    writeFileSync(
      outPath,
      JSON.stringify(
        {
          timestamp: new Date().toISOString(),
          models: MODELS,
          question_count: questions.length,
          dry_run: dryRun,
          results,
        },
        null,
        2,
      ),
    );
  };

  // Save on Ctrl+C and on uncaught errors
  let interrupted = false;
  const handleSignal = () => {
    if (interrupted) process.exit(130);
    interrupted = true;
    console.log("\n\n[interrupt] Persisting results before exit...");
    persist();
    console.log(`[interrupt] Saved ${results.length} results to ${outPath}`);
    console.log(`[resume] tsx scripts/run_eval.ts --resume=${outPath}`);
    process.exit(130);
  };
  process.on("SIGINT", handleSignal);
  process.on("SIGTERM", handleSignal);

  // Write empty/initial file so the path exists
  persist();

  let aborted = false;
  outer: for (let qi = 0; qi < questions.length; qi++) {
    const q = questions[qi];

    if (processedQids.has(q.id)) {
      console.log(`[${qi + 1}/${questions.length}] ${q.id}: SKIP (already done)`);
      continue;
    }

    console.log(`[${qi + 1}/${questions.length}] ${q.id}: ${q.question.slice(0, 70)}...`);

    // Compute the ChronicleDB memory block ONCE per question.
    // It doesn't depend on the answering model — same retrieval for all 3.
    // This cuts embedding calls from N×3 to N (saves 2/3 of embed cost).
    let cachedMemoryBlock = "";
    let cachedRetrievalError: string | null = null;
    try {
      const retrieval = await retrieve({
        chatId: CHAT_ID,
        activeCharacters: [CHARACTER_NAME, USER_NAME],
        recentText: q.question,
        maxTokens: 2000,
      });
      cachedMemoryBlock = retrieval.memoryBlock || "";
    } catch (err) {
      cachedRetrievalError = (err as Error).message;
      if (isRateLimit(cachedRetrievalError)) {
        console.error(`\n[CIRCUIT BREAKER] Rate limit on retrieval embed: ${cachedRetrievalError}`);
        console.error("[CIRCUIT BREAKER] Stopping eval. Resume after the limit resets:");
        console.error(`  npx tsx scripts/run_eval.ts --resume=${outPath}\n`);
        aborted = true;
        break outer;
      }
    }

    for (const modelKey of modelKeys) {
      process.stdout.write(`   ${modelKey} (${MODELS[modelKey]})... `);
      const t0 = Date.now();
      try {
        const qResults = await runQuestion(q, modelKey, fullText, cachedMemoryBlock, cachedRetrievalError);
        results.push(...qResults);
        const errors = qResults.filter((r) => r.error).length;
        console.log(`${errors === 0 ? "ok" : `${errors} errors`} (${Date.now() - t0}ms)`);
      } catch (err) {
        if (err instanceof RateLimitError) {
          console.log(`RATE LIMIT (${Date.now() - t0}ms)`);
          console.error(`\n[CIRCUIT BREAKER] Rate limit on ${modelKey}: ${err.message}`);
          console.error("[CIRCUIT BREAKER] Stopping eval. Resume after the limit resets:");
          console.error(`  npx tsx scripts/run_eval.ts --resume=${outPath}\n`);
          aborted = true;
          persist();
          break outer;
        }
        throw err;
      }
      // Rate limit pacing
      await new Promise((r) => setTimeout(r, 500));
    }

    // Persist after every question — if we crash, we've at minimum got
    // everything up to the previous question.
    persist();
  }

  if (aborted) {
    console.log(`\n[partial] ${results.length} results saved to ${outPath}`);
    process.exit(2);
  }

  console.log(`\nWrote ${results.length} results to ${outPath}`);
  console.log(`\nNext: tsx scripts/score.ts ${outPath}`);
}

main().catch((err) => {
  console.error("Failed:", err);
  process.exit(1);
});
